// Add isLoading to propTypes
AuthForm.propTypes = {
  // ... existing propTypes
  isLoading: PropTypes.bool
};

// Update submit button
<button 
  type="submit" 
  className="submit-btn"
  disabled={isLoading}  // Disable during loading
>
  {isLoading ? (
    <span className="spinner"></span>  // Add loading indicator
  ) : (
    type === 'login' ? 'Login' : 'Sign Up'
  )}
</button>
